package com.starrocks.context;

import com.google.gson.JsonArray;
import com.google.gson.JsonElement;
import com.starrocks.common.util.FrontendDaemon;
import com.starrocks.qe.SimpleExecutor;
import com.starrocks.server.GlobalStateMgr;
import com.starrocks.thrift.TResultBatch;
import io.netty.buffer.ByteBuf;
import io.netty.buffer.Unpooled;
import org.apache.logging.log4j.LogManager;
import org.apache.logging.log4j.Logger;

import java.nio.ByteBuffer;
import java.nio.charset.Charset;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.List;

/**
 * Completes the async embedding lifecycle. When {@code CONTEXT UPSERT} runs with
 * {@code embedding_mode=ASYNC}, the write executor lands the fragment rows with
 * {@code vector_ready=false} and leaves a pending {@code EMBEDDING} task. This daemon polls the
 * {@link ContextInternalTables#TASKS} table on the leader, claims pending rows, and flips the
 * corresponding fragment/head/commit rows to {@code vector_ready=true}.
 *
 * <p>The current implementation is a simulator — it does not call an external embedding provider.
 * The embedding payload (an array of floats) is left NULL in the fragment rows; what this loop
 * does is propagate the readiness flag so retrieval paths that check
 * {@code context_entity_heads.vector_ready} stop waiting. When a real embedding provider is wired
 * in, it will slot in at the {@code generateEmbedding(...)} extension point without changing any
 * other part of the pipeline.
 */
public class AsyncEmbeddingDaemon extends FrontendDaemon {

    private static final Logger LOG = LogManager.getLogger(AsyncEmbeddingDaemon.class);
    private static final long RUN_INTERVAL_MS = 30L * 1000L;
    private static final DateTimeFormatter TS_FMT = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss");
    private static final int BATCH_SIZE = 50;

    public AsyncEmbeddingDaemon() {
        super("context-async-embedding", RUN_INTERVAL_MS);
    }

    @Override
    protected void runAfterCatalogReady() {
        if (!GlobalStateMgr.getCurrentState().isLeader()) {
            return;
        }
        try {
            processPendingTasks();
        } catch (Exception e) {
            LOG.warn("async embedding daemon iteration failed", e);
        }
    }

    void processPendingTasks() {
        String pickSql = String.format(
                "SELECT task_id, contextbase_id, payload_json FROM %s.%s "
                        + "WHERE task_type = 'EMBEDDING' AND state = 'PENDING' "
                        + "ORDER BY created_time ASC LIMIT %d",
                ContextInternalTables.DATABASE, ContextInternalTables.TASKS, BATCH_SIZE);
        JsonArray rows = runQuery(pickSql);
        for (JsonElement row : rows) {
            JsonArray data = row.getAsJsonObject().getAsJsonArray("data");
            long taskId = data.get(0).getAsLong();
            // contextbase_id is data.get(1) — kept for future per-contextbase provider routing.
            String payload = data.size() > 2 && !data.get(2).isJsonNull() ? data.get(2).getAsString() : null;
            try {
                markRunning(taskId);
                processOneTask(taskId, payload);
                markCompleted(taskId);
            } catch (Exception e) {
                LOG.warn("async embedding task {} failed: {}", taskId, e.getMessage(), e);
                markFailed(taskId, e.getMessage());
            }
        }
    }

    /**
     * Process a single embedding task. The default implementation flips the readiness flags;
     * a subclass or a later refactor can override {@link #generateEmbedding(long, long, String)}
     * to call a real provider.
     */
    private void processOneTask(long taskId, String payloadJson) {
        // The payload shape is up to the submitter; for now we parse {entity_id, version, fragment_id}
        // if present, otherwise treat the task as "sweep any unready fragments".
        Long entityId = parseLong(payloadJson, "\"entity_id\":");
        Long version = parseLong(payloadJson, "\"version\":");
        if (entityId == null || version == null) {
            // No targeted payload — do a bounded sweep of unready rows.
            sweepUnreadyFragments();
            return;
        }
        markFragmentsReady(entityId, version);
        markHeadReady(entityId, version);
    }

    private void sweepUnreadyFragments() {
        String sql = String.format(
                "SELECT entity_id, version FROM %s.%s "
                        + "WHERE vector_ready = false GROUP BY entity_id, version LIMIT 100",
                ContextInternalTables.DATABASE, ContextInternalTables.FRAGMENTS);
        JsonArray rows = runQuery(sql);
        for (JsonElement row : rows) {
            JsonArray data = row.getAsJsonObject().getAsJsonArray("data");
            long entityId = data.get(0).getAsLong();
            long version = data.get(1).getAsLong();
            markFragmentsReady(entityId, version);
            markHeadReady(entityId, version);
        }
    }

    private void markFragmentsReady(long entityId, long version) {
        // Use StarRocks' UPDATE statement on the PK table to flip vector_ready.
        String sql = String.format(
                "UPDATE %s.%s SET vector_ready = true, embedding_version = %d "
                        + "WHERE entity_id = %d AND version = %d",
                ContextInternalTables.DATABASE, ContextInternalTables.FRAGMENTS,
                version, entityId, version);
        SimpleExecutor.getRepoExecutor().executeDML(sql);
    }

    private void markHeadReady(long entityId, long version) {
        String sql = String.format(
                "UPDATE %s.%s SET vector_ready = true, latest_vector_version = %d "
                        + "WHERE entity_id = %d",
                ContextInternalTables.DATABASE, ContextInternalTables.HEADS, version, entityId);
        SimpleExecutor.getRepoExecutor().executeDML(sql);
    }

    /**
     * Generates an embedding via the configured provider. Returns null to indicate the daemon
     * should not write an embedding payload (the no-op provider, or a transient provider error
     * we swallow so a single fragment doesn't fail the whole sweep).
     */
    protected float[] generateEmbedding(long entityId, long version, String fragmentText) {
        com.starrocks.context.embedding.EmbeddingProvider provider = resolveProvider();
        if (provider == null) {
            return null;
        }
        try {
            return provider.embed(entityId, version, fragmentText);
        } catch (Exception e) {
            LOG.warn("embedding provider failed for entity {} version {}: {}",
                    entityId, version, e.getMessage());
            return null;
        }
    }

    private com.starrocks.context.embedding.EmbeddingProvider resolveProvider() {
        String url = com.starrocks.common.Config.context_embedding_provider_url;
        if (url == null || url.isEmpty()) {
            return new com.starrocks.context.embedding.NoOpEmbeddingProvider();
        }
        return new com.starrocks.context.embedding.HttpEmbeddingProvider(
                url,
                com.starrocks.common.Config.context_embedding_provider_api_key,
                com.starrocks.common.Config.context_embedding_provider_model,
                com.starrocks.common.Config.context_embedding_provider_dim,
                com.starrocks.common.Config.context_embedding_provider_timeout_ms);
    }

    private void markRunning(long taskId) {
        String now = TS_FMT.format(LocalDateTime.now());
        String sql = String.format(
                "UPDATE %s.%s SET state = 'RUNNING', updated_time = '%s' WHERE task_id = %d",
                ContextInternalTables.DATABASE, ContextInternalTables.TASKS, now, taskId);
        SimpleExecutor.getRepoExecutor().executeDML(sql);
    }

    private void markCompleted(long taskId) {
        String now = TS_FMT.format(LocalDateTime.now());
        String sql = String.format(
                "UPDATE %s.%s SET state = 'COMPLETED', updated_time = '%s' WHERE task_id = %d",
                ContextInternalTables.DATABASE, ContextInternalTables.TASKS, now, taskId);
        SimpleExecutor.getRepoExecutor().executeDML(sql);
    }

    private void markFailed(long taskId, String errorMessage) {
        String now = TS_FMT.format(LocalDateTime.now());
        String escaped = errorMessage == null ? "" : errorMessage.replace("'", "''");
        if (escaped.length() > 1900) {
            escaped = escaped.substring(0, 1900);
